import React, { Fragment, useState, useEffect } from 'react'
import {
    Form, Input, InputNumber, Select,
    Upload, message, DatePicker
} from 'antd';
import { InboxOutlined } from '@ant-design/icons';

const { Dragger } = Upload;
const { Option } = Select;

const InformasiDetail = (props) => {

    const files = {
        name: 'file',
        multiple: true,
        action: 'https://www.mocky.io/v2/5cc8019d300000980a055e76',
        onChange(info) {
            const { status } = info.file;
            if (status !== 'uploading') {
                console.log(info.file, info.fileList);
            }
            if (status === 'done') {
                message.success(`${info.file.name} file uploaded successfully.`);
            } else if (status === 'error') {
                message.error(`${info.file.name} file upload failed.`);
            }
        },
        onDrop(e) {
            console.log('Dropped files', e.dataTransfer.files);
        },
    };

    return (
        <Fragment>
            <Form.Item label="Dokumen Kontrak">
                <Dragger {...files}>
                    <p className="ant-upload-drag-icon">
                        <InboxOutlined />
                    </p>
                    <p className="ant-upload-text">Klik atau drag file pada area ini untuk upload</p>
                </Dragger>
            </Form.Item>

            <Form.Item label="Batas Garansi">
                <DatePicker style={{width: '100%'}}/>
            </Form.Item>

            <Form.Item label="Kepemilikan/Kepemilikan Lain" style={{ marginBottom: 0 }}>   
                <Form.Item label="Kepemilikan"
                    name="year"
                    rules={[{ required: false }]}
                    style={{ display: 'inline-block', width: 'calc(50%)' }}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item> 

                <Form.Item label="Kepemilikan Lain"
                    name="month"
                    rules={[{ required: false }]}
                    style={{ display: 'inline-block', width: 'calc(50%)'}}
                >
                    <Input placeholder="Input birth month" />
                </Form.Item>
            </Form.Item>

            <Form.Item label="Status">
                <Select placeholder="Select province">
                    <Option value="Zhejiang">Zhejiang</Option>
                    <Option value="Jiangsu">Jiangsu</Option>
                </Select>
            </Form.Item>

            <Form.Item label="Daya Listrik & Satuan" style={{ marginBottom: 0 }}>

                <Form.Item label="Daya Listrik"
                    name="month"
                    rules={[{ required: false }]}
                    style={{ display: 'inline-block', width: 'calc(50%)',}}
                >
                    <InputNumber style={{width: '100%'}} />
                </Form.Item>

                <Form.Item label="Satuan"
                    name="year"
                    rules={[{ required: false }]}
                    style={{ display: 'inline-block', width: 'calc(50%)' }}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

            </Form.Item>

            <Form.Item label="Keterangan">
                <Input.TextArea />
            </Form.Item>

        </Fragment>
    )
}

export default InformasiDetail